import Topbar from "./Topbar";
import { Box } from "@mui/material";

export default function DashboardLayout({ children }) {
  return (
    <>
      <Topbar />

      <Box
        sx={{
          pt: "80px", // 🔥 correct top spacing
          px: 3,
          minHeight: "100vh",
          background: "linear-gradient(135deg, #0f2027, #203a43, #2c5364)", // 🔥 FULL BACKGROUND
        }}
      >
        {children}
      </Box>
    </>
  );
}
